import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Box, TextField, Button, Alert, IconButton, CircularProgress } from '@mui/material';
import axios from '../../../../Helpers/FetchCsrfToken';
import FAWTable from '../../FAWTable/FAWTable';
import FAWTypography from '../../FAWTypography';
import FAWTooltip from '../../FAWTooltip';
import FAWConfirmDialogue from '../../FAWConfirmDialogue';
import { showToast } from '../../shared/ToastManager';
import { colors } from '../../../../utils/designTokens';
import ArrowLeftIcon from "@diligentcorp/atlas-react-icons/dist/esm/lens/ArrowLeft.js";

/**
 * AttachmentView Component
 * 
 * A React component for managing work item attachments with direct API calls.
 * Supports upload, delete, download, and restore functionality.
 */
const AttachmentView = ({
  onBack,
  relateId = 0,
  relateTypeCode = '',
  sourceElement = 'WorkItemAttachmentButton',
  initialAttachments = [],
  onAttachmentsChange = null
}) => {
  // State
  const [description, setDescription] = useState('');
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [attachments, setAttachments] = useState([]);
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [error, setError] = useState(null);
  const [successMessage, setSuccessMessage] = useState(null);
  const [confirmDelete, setConfirmDelete] = useState({ open: false, attachment: null });
  
  // Refs
  const fileInputRef = useRef(null);

  // Initialize attachments from props
  useEffect(() => {
    if (initialAttachments && Array.isArray(initialAttachments)) {
      setAttachments(initialAttachments);
    } else {
      setAttachments([]);
    }
  }, [initialAttachments]);

  // Fetch fresh attachments on mount
  useEffect(() => {
    if (relateId && relateTypeCode) {
      fetchAttachments();
    }
  }, [relateId, relateTypeCode]); // eslint-disable-line react-hooks/exhaustive-deps

  /**
   * Fetch attachments from API
   */
  const fetchAttachments = useCallback(async () => {
    if (!relateId || !relateTypeCode) return;
    
    try {
      setLoading(true);
      const response = await axios.get('/Attachment/GetAttachmentsJson', {
        params: {
          relateId,
          relateTypeCode,
          sourceElement
        }
      });
      
      if (response.data && response.data.success && response.data.attachments) {
        const mappedAttachments = response.data.attachments.map(att => ({
          id: att.Id?.toString() || att.id?.toString(),
          name: att.Name || att.name || '',
          size: att.Size?.toString() || att.size?.toString() || '0',
          sizeText: att.SizeText || att.sizeText || '',
          type: att.Type || att.type || '',
          description: att.Description || att.description || '',
          isMarkedForDelete: att.IsMarkedForDelete || att.isMarkedForDelete || false
        }));
        setAttachments(mappedAttachments);
        
        if (onAttachmentsChange) {
          onAttachmentsChange(mappedAttachments);
        }
      } else if (response.data && !response.data.success) {
        showToast.error(response.data?.message || 'Failed to load attachments');
      }
    } catch (err) {
      console.error('Error fetching attachments:', err);
      showToast.error('Failed to load attachments');
    } finally {
      setLoading(false);
    }
  }, [relateId, relateTypeCode, sourceElement, onAttachmentsChange]);

  /**
   * Handle file input change
   */
  const handleFileChange = (event) => {
    const files = Array.from(event.target.files || []);
    setSelectedFiles(files);
    setError(null);
  };

  /**
   * Handle browse button click
   */
  const handleBrowseClick = () => {
    if (fileInputRef.current) {
      fileInputRef.current.click();
    }
  };

  /**
   * Upload attachments via API
   */
  const handleUpload = async () => {
    if (!selectedFiles.length) {
      setError('Please select a file to upload');
      return;
    }

    try {
      setUploading(true);
      setError(null);
      
      const formData = new FormData();
      formData.append('RelateId', relateId.toString());
      formData.append('RelateTypeCode', relateTypeCode);
      formData.append('SourceElement', sourceElement);
      formData.append('NewAttachment.Description', description);
      
      // Add files
      selectedFiles.forEach(file => {
        formData.append('AttachmentList', file);
      });

      const response = await axios.post('/Attachment/SaveAttachmentsJson', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      if (response.data && response.data.success) {
        showToast.success(response.data.message || 'File uploaded successfully');
        setSelectedFiles([]);
        setDescription('');
        
        // Reset file input
        if (fileInputRef.current) {
          fileInputRef.current.value = '';
        }
        
        // Fetch fresh attachments list
        await fetchAttachments();
      } else {
        setError(response.data?.message || 'Upload failed');
        showToast.error(response.data?.message || 'Upload failed');
      }
    } catch (err) {
      console.error('Upload error:', err);
      const errorMsg = err.response?.data?.message || err.message || 'Upload failed';
      setError(errorMsg);
      showToast.error(errorMsg);
    } finally {
      setUploading(false);
    }
  };

  /**
   * Delete attachment via API
   */
  const handleDelete = async (data) => {
    const attachmentId = data.id || data;
    
    try {
      setLoading(true);
      
      const response = await axios.post('/Attachment/DeleteAttachmentJson', {
        attachmentId: parseInt(attachmentId, 10),
        relateId,
        relateTypeCode
      });

      if (response.data && response.data.success) {
        showToast.success('Attachment deleted successfully');
        
        // Remove from local state
        const updatedAttachments = attachments.filter(att => att.id !== attachmentId);
        setAttachments(updatedAttachments);
        
        if (onAttachmentsChange) {
          onAttachmentsChange(updatedAttachments);
        }
      } else {
        showToast.error(response.data?.message || 'Failed to delete attachment');
      }
    } catch (err) {
      console.error('Delete error:', err);
      showToast.error(err.response?.data?.message || 'Failed to delete attachment');
    } finally {
      setLoading(false);
      setConfirmDelete({ open: false, attachment: null });
    }
  };

  /**
   * Download attachment
   */
  const handleDownload = (data) => {
    const attachmentId = data.id || data;
    const url = `/Attachment/DownloadAttachment?attachmentId=${attachmentId}`;
    window.open(url, '_blank');
  };

  /**
   * Handle back button
   */
  const handleBack = () => {
    if (typeof onBack === 'string' && window[onBack]) {
      window[onBack]();
    } else if (typeof onBack === 'function') {
      onBack();
    }
  };

  // Get display file names
  const fileNames = selectedFiles.map(f => f.name).join(', ');

  return (
    <Box sx={{ width: '100%' }}>
      {/* Header */}
      <Box
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 3,
          paddingY: 1,
        }}
      >
        <Box
          sx={{
            display: 'flex',
            alignItems: 'center',
            gap: 1.5,
            flex: 1,
          }}
        >
          {onBack && (
            <FAWTooltip title="Go back">
              <IconButton
                onClick={handleBack}
                sx={{
                  padding: 1,
                  '&:hover': {
                    backgroundColor: 'rgba(0, 0, 0, 0.04)',
                  },
                }}
                aria-label="Go back"
              >
                <ArrowLeftIcon size="md" />
              </IconButton>
            </FAWTooltip>
          )}
          <FAWTypography
            variant="h6"
            sx={{
              fontWeight: 600,
              fontSize: '22px',
              lineHeight: '28px',
              color: colors.type.default,
            }}
          >
            Attachments
          </FAWTypography>
        </Box>
      </Box>

      <Box sx={{ p: 3 }}>
        {/* Error/Success Messages */}
        {error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={() => setError(null)}>
            {error}
          </Alert>
        )}
        {successMessage && (
          <Alert severity="success" sx={{ mb: 2 }} onClose={() => setSuccessMessage(null)}>
            {successMessage}
          </Alert>
        )}

        {/* Hidden file input */}
        <input
          ref={fileInputRef}
          type="file"
          multiple
          style={{ display: 'none' }}
          onChange={handleFileChange}
        />

        {/* Add Attachment Section */}
        <Box sx={{ mb: 3 }}>
          <Box sx={{ mb: 2, fontWeight: 600, fontSize: '14px' }}>Add Attachment</Box>
          <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
            <Button
              variant="contained"
              component="span"
              onClick={handleBrowseClick}
              disabled={uploading}
              sx={{ minWidth: '120px' }}
            >
              Browse...
            </Button>
            <TextField
              fullWidth
              placeholder="No file selected"
              value={fileNames}
              InputProps={{
                readOnly: true,
              }}
              size="small"
            />
            <Button
              variant="contained"
              color="primary"
              onClick={handleUpload}
              disabled={!fileNames || uploading}
              sx={{ minWidth: '100px' }}
              startIcon={uploading ? <CircularProgress size={16} color="inherit" /> : null}
            >
              {uploading ? 'Uploading...' : 'Upload'}
            </Button>
          </Box>
        </Box>

        {/* Description Section */}
        <Box sx={{ mb: 3 }}>
          <Box sx={{ mb: 2, fontWeight: 600, fontSize: '14px' }}>Description</Box>
          <TextField
            fullWidth
            multiline
            rows={3}
            placeholder="Enter attachment description"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            size="small"
            inputProps={{ maxLength: 100 }}
            helperText={`${description.length}/100`}
            disabled={uploading}
          />
        </Box>

        {/* Divider - only show if there are attachments */}
        {attachments.length > 0 && (
          <Box sx={{ borderTop: `1px solid ${colors.ui.border.static}`, my: 3 }} />
        )}

        {/* Attachments List */}
        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', p: 3 }}>
            <CircularProgress size={32} />
          </Box>
        ) : attachments && attachments.length > 0 ? (
          <Box>
            <Box sx={{ mb: 2, fontWeight: 600, fontSize: '14px' }}>Attachments</Box>
            <Box sx={{ width: '100%' }}>
              <FAWTable
                rows={attachments.map(att => ({
                  id: att.id,
                  name: att.name,
                  size: att.size,
                  sizeText: att.sizeText,
                  type: att.type,
                  description: att.description || ''
                }))}
                columns={[
                  {
                    field: 'name',
                    headerName: 'Name',
                    flex: 1,
                    minWidth: 150,
                    align: 'left',
                    headerAlign: 'left',
                    renderCell: (params) => (
                      <FAWTypography sx={{ fontWeight: 500 }}>{params.value}</FAWTypography>
                    )
                  },
                  {
                    field: 'description',
                    headerName: 'Description',
                    flex: 2,
                    minWidth: 200,
                    align: 'left',
                    headerAlign: 'left',
                    renderCell: (params) => (
                      <FAWTypography sx={{ fontSize: '14px', color: '#6f7377' }}>
                        {params.value || '-'}
                      </FAWTypography>
                    )
                  },
                  {
                    field: 'sizeText',
                    headerName: 'Size',
                    width: 120,
                    align: 'left',
                    headerAlign: 'left',
                    renderCell: (params) => (
                      <FAWTypography sx={{ fontSize: '14px', color: '#6f7377' }}>
                        {params.value || '-'}
                      </FAWTypography>
                    )
                  }
                ]}
                actions={[
                  {
                    icon: 'download',
                    onClick: (row) => handleDownload(row),
                    tooltip: 'Download'
                  },
                  {
                    icon: 'delete',
                    onClick: (row) => setConfirmDelete({ open: true, attachment: row }),
                    tooltip: 'Delete'
                  }
                ]}
                showPagination={true}
                autoHeight={true}
                showToolbar={false}
                showFilter={false}
                showSearch={false}
                showColumns={false}
                showExport={false}
                hideReset={true}
                enableMultiSelect={false}
                checkboxSelection={false}
                hideFooter={false}
                emptyStateTitle="No attachments"
                emptyStateMessage="No attachments found."
              />
            </Box>
          </Box>
        ) : null}

      </Box>

      {/* Delete Confirmation Dialog */}
      <FAWConfirmDialogue
        open={confirmDelete.open}
        title="Delete Attachment"
        message={
          confirmDelete.attachment ? (
            <span>
              Are you sure you want to delete <strong>{confirmDelete.attachment.name}</strong>?
            </span>
          ) : 'Are you sure you want to delete this attachment?'
        }
        onConfirm={() => handleDelete(confirmDelete.attachment)}
        onClose={() => setConfirmDelete({ open: false, attachment: null })}
        confirmLabel="Delete"
        cancelLabel="Cancel"
        variant="delete"
      />
    </Box>
  );
};

export default AttachmentView;
