import React, { useState, useCallback } from 'react';
import FAWToast from '../FAWToast';

// Global toast state
let globalToastState = {
  open: false,
  message: '',
  type: 'info',
  duration: 30000
};

let globalSetToastState = null;

// Toast Manager Component - Should be rendered once at the app root
export const ToastManager = () => {
  const [toast, setToast] = useState(globalToastState);

  // Set the global setter function
  React.useEffect(() => {
    globalSetToastState = setToast;
  }, []);

  const handleToastClose = useCallback(() => {
    setToast(prev => ({ ...prev, open: false }));
  }, []);

  return (
    <FAWToast
      open={toast.open}
      message={toast.message}
      type={toast.type}
      duration={toast.duration}
      onClose={handleToastClose}
    />
  );
};

// Central toast utility functions
export const showToast = {
  success: (message, duration = 30000) => {
    if (globalSetToastState) {
      globalSetToastState({
        open: true,
        message,
        type: 'success',
        duration
      });
    } else {
      console.warn('ToastManager not mounted. Toast not shown:', message);
    }
  },

  error: (message, duration = 30000) => {
    if (globalSetToastState) {
      globalSetToastState({
        open: true,
        message,
        type: 'error',
        duration
      });
    } else {
      console.warn('ToastManager not mounted. Toast not shown:', message);
    }
  },

  info: (message, duration = 3000) => {
    if (globalSetToastState) {
      globalSetToastState({
        open: true,
        message,
        type: 'info',
        duration
      });
    } else {
      console.warn('ToastManager not mounted. Toast not shown:', message);
    }
  },

  warning: (message, duration = 4000) => {
    if (globalSetToastState) {
      globalSetToastState({
        open: true,
        message,
        type: 'warning',
        duration
      });
    } else {
      console.warn('ToastManager not mounted. Toast not shown:', message);
    }
  },

  // Generic method
  show: (message, type = 'info', duration = 30000) => {
    if (globalSetToastState) {
      globalSetToastState({
        open: true,
        message,
        type,
        duration
      });
    } else {
      console.warn('ToastManager not mounted. Toast not shown:', message);
    }
  }
};

export default showToast;
